import * as esbuild from 'esbuild';
import fs from 'fs';
import path from 'path';
import { builtinModules } from 'module';

function collectFiles(dir, baseDir, results = {}) {
  if (!fs.existsSync(dir)) return results;
  const items = fs.readdirSync(dir);
  for (const item of items) {
    const fullPath = path.join(dir, item);
    const relPath = path.relative(baseDir, fullPath);
    if (fs.statSync(fullPath).isDirectory()) {
      collectFiles(fullPath, baseDir, results);
    } else {
      results[relPath] = fs.readFileSync(fullPath, 'utf8');
    }
  }
  return results;
}

async function bundle() {
  console.log('Embedding assets...');
  const assets = {};
  
  Object.assign(assets, collectFiles('src/stdlib', 'src', {}));
  Object.assign(assets, collectFiles('src/runtime', 'src', {}));

  const assetsContent = `/**
 * Virtual Asset Store for Sky Compiler.
 * 
 * THIS FILE IS AUTOMATICALLY GENERATED BY bundle.js.
 * DO NOT EDIT MANUALLY.
 */

export const VIRTUAL_ASSETS: Record<string, string> = ${JSON.stringify(assets, null, 2)};

export function hasVirtualAsset(path: string): boolean {
  return path in VIRTUAL_ASSETS;
}

export function readVirtualAsset(path: string): string {
  if (path in VIRTUAL_ASSETS) {
    return VIRTUAL_ASSETS[path];
  }
  throw new Error(\`Virtual asset not found: \${path}\`);
}

export function listVirtualAssets(prefix: string): string[] {
  return Object.keys(VIRTUAL_ASSETS).filter(p => p.startsWith(prefix));
}
`;

  fs.writeFileSync('src/assets.ts', assetsContent);

  const commonOptions = {
    bundle: true,
    platform: 'node',
    format: 'esm',
    target: 'node20',
    minify: true,
    sourcemap: false,
    external: [...builtinModules, ...builtinModules.map(m => `node:${m}`), 'fsevents'],
  };

  console.log('Bundling sky...');
  await esbuild.build({
    ...commonOptions,
    entryPoints: ['src/bin/sky.ts'],
    outfile: 'dist/bin/sky',
  });
  prependShebang('dist/bin/sky');

  console.log('Bundling sky-lsp...');
  await esbuild.build({
    ...commonOptions,
    entryPoints: ['src/bin/sky-lsp.ts'],
    outfile: 'dist/bin/sky-lsp',
  });
  prependShebang('dist/bin/sky-lsp');

  // We still copy them for local development
  console.log('Copying physical assets...');
  fs.mkdirSync('dist/stdlib', { recursive: true });
  fs.cpSync('src/stdlib', 'dist/stdlib', { recursive: true });
  fs.mkdirSync('dist/runtime', { recursive: true });
  fs.cpSync('src/runtime', 'dist/runtime', { recursive: true });

  console.log('Done!');
}

function prependShebang(filePath) {
  const shebang = Buffer.from([
    '#!/usr/bin/env node',
    'import { createRequire as __createRequire } from "module";',
    'import { fileURLToPath as __fileURLToPath } from "url";',
    'import { dirname as __pathDirname } from "path";',
    'const require = __createRequire(import.meta.url);',
    'const __filename = __fileURLToPath(import.meta.url);',
    'const __dirname = __pathDirname(__filename);',
    ''
  ].join('\n'));
  
  const content = fs.readFileSync(filePath);
  const combined = Buffer.concat([shebang, content]);
  fs.writeFileSync(filePath, combined);
  fs.chmodSync(filePath, '755');
}

bundle().catch((err) => {
  console.error(err);
  process.exit(1);
});
